// ─────────────────────────────────────────────────────────────
// 채점 엔진 (3단계 파이프라인)
// ─────────────────────────────────────────────────────────────

// Stage 1: 유형별 원시 점수 집계 (Normative — 문항별 독립 1~6점)
// 혼합 블록(F1~F6): 선지 key = 유형 key, 점수 직접 합산
// 순수 축 블록(F7 θ1, F8 θ2): 같은 극성(pole) 유형 쌍에 점수를 1/2씩 배분
function calcRawScores(answers) {
  const raw = { 이론실행: 0, 경험실행: 0, 이론사고: 0, 경험사고: 0 };

  const applyAxisScore = (axisType, pole, score) => {
    if (axisType === "θ1") {
      if (pole === "이론") { raw.이론실행 += score / 2; raw.이론사고 += score / 2; }
      else                { raw.경험실행 += score / 2; raw.경험사고 += score / 2; }
    } else {
      if (pole === "실행") { raw.이론실행 += score / 2; raw.경험실행 += score / 2; }
      else                { raw.이론사고 += score / 2; raw.경험사고 += score / 2; }
    }
  };

  FRAMES.forEach(f => {
    const a = answers[f.id];
    if (!a) return;
    f.stmts.forEach(stmt => {
      const score = a[stmt.key];
      if (!score) return;
      if (f.axisType) {
        applyAxisScore(f.axisType, stmt.pole, score);
      } else {
        raw[stmt.key] += score;
      }
    });
  });
  return raw;
}

// Stage 2: 2축 점수 계산
// θ₁ = 태소 축 (양수=태, 음수=소), θ₂ = 양음 축 (양수=양, 음수=음)
function calcAxisScores(raw) {
  const θ1 = (raw.이론실행 + raw.이론사고) - (raw.경험실행 + raw.경험사고);
  const θ2 = (raw.이론실행 + raw.경험실행) - (raw.이론사고 + raw.경험사고);
  return { θ1, θ2 };
}

// Stage 3: 베이지안 사후 확률 계산
// 각 유형의 중심점(μ)과 분산(σ²)으로 가우시안 우도 계산
// 8프레임 기준: 순수 유형 기대 θ ≈ ±22, 범위 ≈ ±60
// normative 6점 기준: 순수 유형 θ 기대값 ≈ ±40, 실용 mu ≈ ±34, sigma = 21, maxRange = 48
const TYPE_PARAMS = {
  이론실행: { mu1:  34, mu2:  34, sigma: 21, prior: 0.25 },
  경험실행: { mu1: -34, mu2:  34, sigma: 21, prior: 0.25 },
  이론사고: { mu1:  34, mu2: -34, sigma: 21, prior: 0.25 },
  경험사고: { mu1: -34, mu2: -34, sigma: 21, prior: 0.25 },
};

function gaussianPdf(x, mu, sigma) {
  const z = (x - mu) / sigma;
  return Math.exp(-0.5 * z * z);
}

function calcTypeProbabilities(θ1, θ2) {
  const types = ["이론실행", "경험실행", "이론사고", "경험사고"];
  const likelihoods = {};
  types.forEach(t => {
    const p = TYPE_PARAMS[t];
    likelihoods[t] = gaussianPdf(θ1, p.mu1, p.sigma)
                   * gaussianPdf(θ2, p.mu2, p.sigma)
                   * p.prior;
  });
  const total = Object.values(likelihoods).reduce((s, v) => s + v, 0);
  const probs = {};
  types.forEach(t => { probs[t] = total > 0 ? likelihoods[t] / total : 0.25; });
  return probs;
}

function getClassification(probs) {
  const types = ["이론실행", "경험실행", "이론사고", "경험사고"];
  const sorted = [...types].sort((a, b) => probs[b] - probs[a]);
  const topType = sorted[0];
  const topProb = probs[topType];
  // 신뢰 등급
  let confidence, confidenceLabel, confidenceColor;
  if (topProb >= 0.70) {
    confidence = "명확"; confidenceLabel = "명확한 유형"; confidenceColor = "#1A6A3A";
  } else if (topProb >= 0.50) {
    confidence = "경향"; confidenceLabel = "경향이 있는 유형"; confidenceColor = "#8A5A00";
  } else {
    confidence = "미결정"; confidenceLabel = "복합 유형 가능"; confidenceColor = "#6A2080";
  }
  return { type: topType, topProb, confidence, confidenceLabel, confidenceColor, sorted, probs };
}

// 통합 calcResult (기존 인터페이스 유지)
function calcResult(answers) {
  const raw = calcRawScores(answers);
  const { θ1, θ2 } = calcAxisScores(raw);
  const probs = calcTypeProbabilities(θ1, θ2);
  const cls = getClassification(probs);

  // v2 호환: 태/소/양/음 퍼센트 계산 (결과 화면 축 바 재사용)
  const maxRange = 48; // normative 6점 8프레임 θ 최대 범위
  const clamp = (v) => Math.max(0, Math.min(100, v));
  const 이론Pct = clamp(Math.round((θ1 + maxRange) / (2 * maxRange) * 100));
  const 경험Pct = 100 - 이론Pct;
  const 실행Pct = clamp(Math.round((θ2 + maxRange) / (2 * maxRange) * 100));
  const 사고Pct = 100 - 실행Pct;

  const specialMatch = cls.topProb >= 0.70;

  return {
    type: cls.type,
    topProb: cls.topProb,
    이론Pct, 경험Pct, 실행Pct, 사고Pct,
    specialMatch,
    probs: cls.probs,
    confidence: cls.confidence,
    confidenceLabel: cls.confidenceLabel,
    confidenceColor: cls.confidenceColor,
    sorted: cls.sorted,
    θ1, θ2,
    raw,
  };
}

